    // Preserve the old compound format so existing documents are still found.
    modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

    // EF Core 9: HasIndex throws for Cosmos entities — Cosmos indexing is
    // managed via the container's indexing policy, not EF Core. Removed.
}

